     1→// HireLoop Main JavaScript
     2→
     3→// Auth state
     4→let currentUser = null;
     5→let _checkAuthPromise = null; // Prevent race conditions with double checkAuth() calls
     6→const TOKEN_KEY = 'rekrutai_token';
     7→const REFRESH_KEY = 'rekrutai_refresh';
     8→
     9→// Handle OAuth callback tokens from URL
    10→function handleOAuthCallback() {
    11→  const params = new URLSearchParams(window.location.search);
    12→  const token = params.get('token');
    13→  const refresh = params.get('refresh');
    14→
    15→  if (token) {
    16→    localStorage.setItem(TOKEN_KEY, token);
    17→    if (refresh) {
    18→      localStorage.setItem(REFRESH_KEY, refresh);
    19→    }
    20→    // Clean URL
    21→    window.history.replaceState({}, document.title, window.location.pathname);
    22→  }
    23→}
    24→
    25→// Refresh access token using refresh token
    26→async function refreshAccessToken() {
    27→  const refreshToken = localStorage.getItem(REFRESH_KEY);
    28→  if (!refreshToken) return null;
    29→
    30→  try {
    31→    const response = await fetch('/api/auth/refresh', {
    32→      method: 'POST',
    33→      headers: { 'Content-Type': 'application/json' },
    34→      body: JSON.stringify({ refreshToken })
    35→    });
    36→
    37→    if (response.ok) {
    38→      const data = await response.json();
    39→      if (data.success) {
    40→        localStorage.setItem(TOKEN_KEY, data.accessToken);
    41→        localStorage.setItem(REFRESH_KEY, data.refreshToken);
    42→        return data.accessToken;
    43→      }
    44→    }
    45→  } catch (err) {
    46→    console.error('Token refresh failed:', err);
    47→  }
    48→
    49→  // Refresh failed - clear tokens
    50→  localStorage.removeItem(TOKEN_KEY);
    51→  localStorage.removeItem(REFRESH_KEY);
    52→  return null;
    53→}
    54→
    55→// Check auth status on page load
    56→// Uses a promise guard to prevent race conditions when called from multiple DOMContentLoaded handlers
    57→async function checkAuth() {
    58→  // If already running, return the existing promise (prevents double token refresh)
    59→  if (_checkAuthPromise) return _checkAuthPromise;
    60→
    61→  _checkAuthPromise = _doCheckAuth();
    62→  try {
    63→    return await _checkAuthPromise;
    64→  } finally {
    65→    _checkAuthPromise = null;
    66→  }
    67→}
    68→
    69→async function _doCheckAuth() {
    70→  // Handle OAuth callback first
    71→  handleOAuthCallback();
    72→
    73→  const token = localStorage.getItem(TOKEN_KEY);
    74→  if (!token) return null;
    75→
    76→  try {
    77→    const response = await fetch('/api/auth/me', {
    78→      headers: { 'Authorization': `Bearer ${token}` }
    79→    });
    80→
    81→    if (response.ok) {
    82→      const data = await response.json();
    83→      currentUser = data.user;
    84→      updateNavForAuth();
    85→      return data.user;
    86→    }
    87→
    88→    // Token expired - try refresh
    89→    if (response.status === 401) {
    90→      const newToken = await refreshAccessToken();
    91→      if (newToken) {
    92→        // Retry with new token (reset promise guard for retry)
    93→        _checkAuthPromise = null;
    94→        return await checkAuth();
    95→      }
    96→    }
    97→  } catch (err) {
    98→    console.error('Auth check failed:', err);
    99→  }
   100→  return null;
   101→}
   102→
   103→// Update navigation based on auth state
   104→function updateNavForAuth() {
   105→  const navAuth = document.getElementById('nav-auth');
   106→  if (!navAuth) return;
   107→
   108→  if (currentUser) {
   109→    const recruiterRoles = ['recruiter', 'hiring_manager', 'employer', 'admin'];
   110→    const dashboardUrl = recruiterRoles.includes(currentUser.role)
   111→      ? '/recruiter-dashboard.html'
   112→      : '/candidate-dashboard.html';
   113→
   114→    navAuth.innerHTML = `
   115→      <span class="user-greeting">Hey, ${currentUser.name || currentUser.email.split('@')[0]}</span>
   116→      <a href="${dashboardUrl}" class="btn btn-primary">Dashboard</a>
   117→    `;
   118→  }
   119→}
   120→
   121→// Registration
   122→async function handleRegister(event) {
   123→  event.preventDefault();
   124→  const form = event.target;
   125→  const submitBtn = form.querySelector('button[type="submit"]');
   126→  const errorEl = document.getElementById('register-error');
   127→
   128→  submitBtn.disabled = true;
   129→  submitBtn.textContent = 'Creating account...';
   130→  if (errorEl) errorEl.style.display = 'none';
   131→
   132→  try {
   133→    const response = await fetch('/api/auth/register', {
   134→      method: 'POST',
   135→      headers: { 'Content-Type': 'application/json' },
   136→      body: JSON.stringify({
   137→        email: form.email.value,
   138→        password: form.password.value,
   139→        name: form.name?.value || '',
   140→        role: form.role?.value || 'candidate',
   141→        company_name: form.company_name?.value || ''
   142→      })
   143→    });
   144→
   145→    const data = await response.json();
   146→
   147→    if (data.success) {
   148→      localStorage.setItem(TOKEN_KEY, data.accessToken || data.token);
   149→      if (data.refreshToken) {
   150→        localStorage.setItem(REFRESH_KEY, data.refreshToken);
   151→      }
   152→      // Redirect based on role - all recruiter-type roles go to recruiter dashboard
   153→      const role = form.role?.value || 'candidate';
   154→      const recruiterRoles = ['recruiter', 'hiring_manager', 'employer', 'admin'];
   155→      window.location.href = recruiterRoles.includes(role)
   156→        ? '/recruiter-dashboard.html'
   157→        : '/candidate-dashboard.html';
   158→    } else {
   159→      if (errorEl) {
   160→        errorEl.textContent = data.error || 'Registration failed';
   161→        errorEl.style.display = 'block';
   162→      }
   163→    }
   164→  } catch (err) {
   165→    if (errorEl) {
   166→      errorEl.textContent = 'Network error. Please try again.';
   167→      errorEl.style.display = 'block';
   168→    }
   169→  } finally {
   170→    submitBtn.disabled = false;
   171→    submitBtn.textContent = 'Create Account';
   172→  }
   173→}
   174→
   175→// Login
   176→async function handleLogin(event) {
   177→  event.preventDefault();
   178→  const form = event.target;
   179→  const submitBtn = form.querySelector('button[type="submit"]');
   180→  const errorEl = document.getElementById('login-error');
   181→
   182→  submitBtn.disabled = true;
   183→  submitBtn.textContent = 'Signing in...';
   184→  if (errorEl) errorEl.style.display = 'none';
   185→
   186→  try {
   187→    const response = await fetch('/api/auth/login', {
   188→      method: 'POST',
   189→      headers: { 'Content-Type': 'application/json' },
   190→      body: JSON.stringify({
   191→        email: form.email.value,
   192→        password: form.password.value
   193→      })
   194→    });
   195→
   196→    const data = await response.json();
   197→
   198→    if (data.success) {
   199→      localStorage.setItem(TOKEN_KEY, data.accessToken || data.token);
   200→      if (data.refreshToken) {
   201→        localStorage.setItem(REFRESH_KEY, data.refreshToken);
   202→      }
   203→      // Redirect based on role - all recruiter-type roles go to recruiter dashboard
   204→      const recruiterRoles = ['recruiter', 'hiring_manager', 'employer', 'admin'];
   205→      window.location.href = recruiterRoles.includes(data.user?.role)
   206→        ? '/recruiter-dashboard.html'
   207→        : '/candidate-dashboard.html';
   208→    } else {
   209→      if (errorEl) {
   210→        errorEl.textContent = data.error || 'Login failed';
   211→        errorEl.style.display = 'block';
   212→      }
   213→    }
   214→  } catch (err) {
   215→    if (errorEl) {
   216→      errorEl.textContent = 'Network error. Please try again.';
   217→      errorEl.style.display = 'block';
   218→    }
   219→  } finally {
   220→    submitBtn.disabled = false;
   221→    submitBtn.textContent = 'Sign In';
   222→  }
   223→}
   224→
   225→// Logout
   226→async function handleLogout() {
   227→  const token = localStorage.getItem(TOKEN_KEY);
   228→  if (token) {
   229→    try {
   230→      await fetch('/api/auth/logout', {
   231→        method: 'POST',
   232→        headers: { 'Authorization': `Bearer ${token}` }
   233→      });
   234→    } catch (e) {
   235→      // Ignore errors during logout
   236→    }
   237→  }
   238→  localStorage.removeItem(TOKEN_KEY);
   239→  localStorage.removeItem(REFRESH_KEY);
   240→  window.location.href = '/';
   241→}
   242→
   243→// API helper with automatic token refresh
   244→async function apiCall(endpoint, options = {}) {
   245→  let token = localStorage.getItem(TOKEN_KEY);
   246→
   247→  // Don't set Content-Type for FormData — browser sets multipart boundary automatically
   248→  const headers = {
   249→    ...(options.isFormData ? {} : { 'Content-Type': 'application/json' }),
   250→    ...(token && { 'Authorization': `Bearer ${token}` }),
   251→    ...options.headers
   252→  };
   253→
   254→  // Strip isFormData from options before passing to fetch
   255→  const { isFormData, ...fetchOptions } = options;
   256→
   257→  let response = await fetch(`/api${endpoint}`, {
   258→    ...fetchOptions,
   259→    headers
   260→  });
   261→
   262→  // If 401 and we have a refresh token, try to refresh
   263→  if (response.status === 401) {
   264→    const newToken = await refreshAccessToken();
   265→    if (newToken) {
   266→      // Retry with new token
   267→      headers['Authorization'] = `Bearer ${newToken}`;
   268→      response = await fetch(`/api${endpoint}`, {
   269→        ...fetchOptions,
   270→        headers
   271→      });
   272→    } else {
   273→      // Still unauthorized - redirect to login
   274→      window.location.href = '/login.html';
   275→      return null;
   276→    }
   277→  }
   278→
   279→  // Handle non-OK responses
   280→  if (!response.ok) {
   281→    const contentType = response.headers.get('content-type') || '';
   282→    if (contentType.includes('application/json')) {
   283→      const errorData = await response.json();
   284→      throw new Error(errorData.error || errorData.message || `API error: ${response.status}`);
   285→    }
   286→    throw new Error(`API error: ${response.status}`);
   287→  }
   288→
   289→  // Safely parse JSON (some endpoints may return non-JSON)
   290→  const contentType = response.headers.get('content-type') || '';
   291→  if (contentType.includes('application/json')) {
   292→    return response.json();
   293→  }
   294→  return { success: true };
   295→}
   296→
   297→// Dashboard functions
   298→async function loadDashboard() {
   299→  const user = await checkAuth();
   300→  if (!user) {
   301→    window.location.href = '/login.html';
   302→    return;
   303→  }
   304→
   305→  // Update user info
   306→  const userNameEl = document.getElementById('user-name');
   307→  if (userNameEl) {
   308→    userNameEl.textContent = user.name || user.email.split('@')[0];
   309→  }
   310→
   311→  // Load stats
   312→  loadInterviewStats();
   313→  loadRecentInterviews();
   314→}
   315→
   316→async function loadInterviewStats() {
   317→  try {
   318→    const data = await apiCall('/interviews/stats/summary');
   319→    if (!data) return;
   320→
   321→    const { stats, recent_scores } = data;
   322→
   323→    // Update stat cards
   324→    const totalEl = document.getElementById('total-interviews');
   325→    const avgEl = document.getElementById('avg-score');
   326→    const bestEl = document.getElementById('best-score');
