   328→    if (totalEl) totalEl.textContent = stats?.completed || 0;
   329→    if (avgEl) avgEl.textContent = stats?.avg_score ? parseFloat(stats.avg_score).toFixed(1) : '-';
   330→    if (bestEl) bestEl.textContent = stats?.best_score || '-';
   331→
   332→  } catch (err) {
   333→    console.error('Failed to load stats:', err);
   334→  }
   335→}
   336→
   337→async function loadRecentInterviews() {
   338→  try {
   339→    const data = await apiCall('/interviews/history?limit=5');
   340→    if (!data) return;
   341→
   342→    const listEl = document.getElementById('recent-interviews');
   343→    if (!listEl) return;
   344→
   345→    if (!data.interviews || data.interviews.length === 0) {
   346→      listEl.innerHTML = `
   347→        <div class="empty-state">
   348→          <p>No interviews yet. Start practicing!</p>
   349→          <a href="/interview.html" class="btn btn-primary">Start Mock Interview</a>
   350→        </div>
   351→      `;
   352→      return;
   353→    }
   354→
   355→    listEl.innerHTML = data.interviews.map(interview => `
   356→      <div class="interview-item">
