   358→          <span class="interview-type">${interview.interview_type}</span>
   359→          <span class="interview-date">${new Date(interview.created_at).toLocaleDateString()}</span>
   360→        </div>
   361→        <div class="interview-score">
   362→          ${interview.overall_score ? `<span class="score">${interview.overall_score}/10</span>` : '<span class="pending">In Progress</span>'}
   363→        </div>
   364→        <a href="/interview.html?id=${interview.id}" class="btn btn-ghost btn-sm">
   365→          ${interview.status === 'completed' ? 'Review' : 'Continue'}
   366→        </a>
   367→      </div>
   368→    `).join('');
   369→
   370→  } catch (err) {
