// Resume upload
async function uploadResume(e) {
  const file = e.target.files[0];
  if (!file) return;

  // Validate file size (10MB max)
  if (file.size > 10 * 1024 * 1024) {
    alert('File too large. Maximum size is 10MB.');
    return;
  }

  const formData = new FormData();
  formData.append('resume', file);

  document.getElementById('resume-dropzone').innerHTML = `
    <div class="spinner"></div>
    <p>Uploading and parsing resume...</p>
  `;

  try {
    const token = localStorage.getItem('rekrutai_token');
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 60000); // 60s timeout

    const response = await fetch('/api/candidate/resume/upload', {
      method: 'POST',
      headers: {
        ...(token && { 'Authorization': `Bearer ${token}` })
      },
      body: formData,
      signal: controller.signal
    });
    clearTimeout(timeoutId);

    const data = await response.json();

    if (data.success) {
      document.getElementById('resume-dropzone').innerHTML = `
        <div class="upload-icon">✅</div>
        <h3>Resume Uploaded!</h3>
        <p>${data.parsed_data ? 'AI has parsed your resume' : 'Resume saved to your profile'}</p>
        <input type="file" id="resume-input" accept=".pdf,.docx,.doc" hidden>
        <button class="btn btn-ghost" onclick="document.getElementById('resume-input').click()">Upload Different</button>
      `;
      document.getElementById('resume-input').addEventListener('change', uploadResume);

      document.getElementById('current-resume').style.display = 'flex';
      document.getElementById('resume-link').href = data.resume_url;
      document.getElementById('resume-name').textContent = file.name;

      if (data.parsed_data) {
        parsedResumeData = data.parsed_data;
        showParsedPreview(data.parsed_data);
      }
    } else {
      // Server returned an error response
      throw new Error(data.error || 'Upload failed');
    }
  } catch (err) {
    const isTimeout = err.name === 'AbortError';
    document.getElementById('resume-dropzone').innerHTML = `
      <div class="upload-icon">❌</div>
      <h3>${isTimeout ? 'Upload Timed Out' : 'Upload Failed'}</h3>
      <p>${isTimeout ? 'The server took too long. Please try again.' : (err.message || 'Please try again')}</p>
      <input type="file" id="resume-input" accept=".pdf,.docx,.doc" hidden>
      <button class="btn btn-primary" onclick="document.getElementById('resume-input').click()">Try Again</button>
    `;
    document.getElementById('resume-input').addEventListener('change', uploadResume);
  }
}

